#include <stdio.h>
#include <stdlib.h>
#define MAX 100001
#define INF 1000000001
// Define the structure for an edge
typedef struct {
    int u, v, w;
} Edge;
// Define the structure for a disjoint set
typedef struct {
    int parent[MAX];
    int rank[MAX];
} DisjointSet;
// Function to find the parent of a node
int find(DisjointSet *ds, int x) {
    if (ds->parent[x] != x) {
        ds->parent[x] = find(ds, ds->parent[x]);
    }
    return ds->parent[x];
}
// Function to union two nodes
void unionSet(DisjointSet *ds, int x, int y) {
    int rootX = find(ds, x);
    int rootY = find(ds, y);
    if (ds->rank[rootX] < ds->rank[rootY]) {
        ds->parent[rootX] = rootY;
    } else if (ds->rank[rootX] > ds->rank[rootY]) {
        ds->parent[rootY] = rootX;
    } else {
        ds->parent[rootY] = rootX;
        ds->rank[rootX]++;
    }
}
// Function to compare two edges
int compareEdges(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->w - e2->w;
}
// Function to find the minimum spanning tree
void findMST(int n, int m, Edge *edges) {
    DisjointSet ds;
    for (int i = 0; i < n; i++) {
        ds.parent[i] = i;
        ds.rank[i] = 0;
    }
    qsort(edges, m, sizeof(Edge), compareEdges);
    for (int i = 0; i < m; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int w = edges[i].w;
        if (find(&ds, u) != find(&ds, v)) {
            unionSet(&ds, u, v);
            printf("[%d, %d, %d] ", u, v, w);
        }
    }
}
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    Edge *edges = (Edge *)malloc(m * sizeof(Edge));
    for (int i = 0; i < m; i++) {
        scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
    }
    findMST(n, m, edges);
    free(edges);
    return 0;
}

